mapper.delete:
DELETE FROM tb_fav
WHERE trgt_type = #{trgtType}
  AND trgt_idx = #{trgtIdx}
  AND mbr_acct_idx = #{mbrAcctIdx}

mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM tb_fav
    WHERE trgt_type = #{trgtType}
      AND trgt_idx = #{trgtIdx}
      AND mbr_acct_idx = #{mbrAcctIdx}
)

SELECT COUNT(*)
FROM tb_fav
WHERE trgt_type = #{trgtType}
  AND trgt_idx = #{trgtIdx}
